// ─── /api/analyze handler ───────────────────────────────────────────────────
// INPUT  (from frontend App.jsx handleRunWorkflow):
//   { taskTitle, taskType, taskBudget: Number, receiverAddress: string }
//
// OUTPUT expected by frontend:
//   { ok: true, analysis: { score, status, summary, source } }
//   { ok: false, message: string }   ← on error

const body = $input.first().json.body;

// ---------- Validate ----------
if (!body.taskTitle || !body.receiverAddress) {
  return [{
    json: {
      ok: false,
      message: 'taskTitle and receiverAddress are required.'
    }
  }];
}

const ALGO_ADDRESS_REGEX = /^[A-Z2-7]{58}$/;
if (!ALGO_ADDRESS_REGEX.test(body.receiverAddress)) {
  return [{
    json: {
      ok: false,
      message: 'receiverAddress is not a valid Algorand address (58-char base32).'
    }
  }];
}

// ---------- Simple keyword-based AI scoring ----------
// Replace this section with a real AI API call (OpenAI, Gemini, etc.)
// if you want LLM-based evaluation.
const SCORING_RULES = [
  { keywords: ['critical', 'security', 'vulnerability', 'urgent'],     score: 92 },
  { keywords: ['payment', 'blockchain', 'algorand', 'smart contract'],  score: 88 },
  { keywords: ['code review', 'refactor', 'architecture'],              score: 82 },
  { keywords: ['feature', 'develop', 'implement', 'build'],             score: 78 },
  { keywords: ['test', 'qa', 'quality', 'verify'],                      score: 74 },
  { keywords: ['bug', 'fix', 'patch', 'repair'],                        score: 70 },
  { keywords: ['document', 'readme', 'wiki', 'write'],                  score: 65 },
];

const titleLower = (body.taskTitle + ' ' + body.taskType).toLowerCase();
let score = 60; // baseline
for (const rule of SCORING_RULES) {
  if (rule.keywords.some(kw => titleLower.includes(kw))) {
    score = rule.score;
    break;
  }
}

// Budget modifier: tasks with higher budgets get a slight boost (capped at 5pts)
const budgetBonus = Math.min(5, Math.floor((body.taskBudget || 0) * 10));
score = Math.min(100, score + budgetBonus);

const status = score >= 75 ? 'completed' : 'failed';

const summaryMap = {
  completed: `Task "${body.taskTitle}" scored ${score}/100 — above the payment threshold. AI evaluation approved.`,
  failed:    `Task "${body.taskTitle}" scored ${score}/100 — below the payment threshold. Payment will be skipped.`
};

return [{
  json: {
    ok: true,
    analysis: {
      score,
      status,
      summary: summaryMap[status],
      source:  'n8n-backend-analysis'
    }
  }
}];

// ─── /api/pay handler ────────────────────────────────────────────────────────
// INPUT  (from frontend App.jsx handleRunWorkflow):
//   { taskId, receiver, score: Number, status: string, amountAlgo: Number }
//
// OUTPUT expected by frontend (skipped path):
//   { ok: true, skipped: true, message: string }
//
// OUTPUT expected by frontend (success path):
//   { ok: true, skipped: false, transactionId, explorerUrl, confirmedRound, note, receiverAddress }
//
// OUTPUT on error:
//   { ok: false, message: string }

const THRESHOLD = 75;
const body = $input.first().json.body;

// ---------- Validate ----------
if (!body.taskId || !body.receiver || body.score === undefined) {
  return [{
    json: {
      ok: false,
      message: 'taskId, receiver, and score are required.'
    }
  }];
}

// ---------- Threshold gate ----------
if (body.score < THRESHOLD || body.status !== 'completed') {
  return [{
    json: {
      ok: true,
      skipped: true,
      message: `Score ${body.score} is below the ${THRESHOLD} threshold — payment skipped.`
    }
  }];
}

// ---------- Algorand payment ----------
// ⚠️  This section calls the Algorand Testnet.
// The HTTP Request node (n6-algorand-pay) handles the actual network call.
// We just pass the validated payload forward.
return [{
  json: {
    _validated: true,
    taskId:     body.taskId,
    receiver:   body.receiver,
    score:      body.score,
    status:     body.status,
    amountAlgo: body.amountAlgo || 0.10
  }
}];

// Map the Algorand pay service response into the shape the frontend expects.
// If the HTTP Request fails, n8n routes to the error branch — see n8-pay-error.

const algoResponse = $input.first().json;
const incoming     = $('Threshold Gate').first().json;

// Build the note payload that gets stored on-chain
const note = {
  taskId: incoming.taskId,
  score:  incoming.score,
  status: incoming.status
};

const txId          = algoResponse.transactionId || algoResponse.txId || 'SIMULATED-TX-ID';
const confirmedRound = algoResponse.confirmedRound || algoResponse.round || 0;
const explorerUrl   = `https://testnet.explorer.perawallet.app/tx/${txId}`;

return [{
  json: {
    ok:              true,
    skipped:         false,
    transactionId:   txId,
    explorerUrl,
    confirmedRound,
    note,
    receiverAddress: incoming.receiver
  }
}];

// Error handler: called when the Algorand pay HTTP request fails.
const error = $input.first().json;
return [{
  json: {
    ok: false,
    message: error.message || error.error || 'Algorand payment service returned an error.'
  }
}];
